class DSU(n: Int) {
    private val parent = Array.tabulate(n)(i => i)
    private val rank = Array.ofDim[Int](n)

    def find(x: Int): Int = {
        if (parent(x) != x) {
            parent(x) = find(parent(x))
        }
        parent(x)
    }

    def union(x: Int, y: Int): Unit = {
        val rx = find(x)
        val ry = find(y)
        if (rx == ry) return

        if (rank(rx) < rank(ry)) {
            parent(rx) = ry
        } else if (rank(rx) > rank(ry)) {
            parent(ry) = rx
        } else {
            parent(ry) = rx
            rank(rx) += 1
        }
    }
}

