def solve(nums: Array[Long]): Long = {
    val n = nums.length
    var sorted = true
    for (i <- 0 until n) {
        if (nums(i) != i) {
            sorted = false
        }
    }
    if (sorted) {
        return 0
    }

    val visited = new Array[Boolean](n)
    val cycles = scala.collection.mutable.ArrayBuffer[scala.collection.mutable.ArrayBuffer[Int]]()

    for (i <- 0 until n) {
        if (!visited(i)) {
            visited(i) = true
            val cycle = scala.collection.mutable.ArrayBuffer[Int](i)
            var current = nums(i).toInt
            while (current != i) {
                visited(current) = true
                cycle += current
                current = nums(current).toInt
            }
            cycles += cycle
        }
    }

    var ans = 0L
    for (bit <- 17 downto 0) {
        val candidate = ans | (1L << bit)
        var valid = true
        for (cycle <- cycles if valid) {
            if (cycle.length > 1) {
                if (!cycle.forall(idx => (nums(idx) & candidate) == candidate)) {
                    valid = false
                }
            }
        }
        if (valid) {
            ans = candidate
        }
    }

    ans
}
